import { BrowserWindow, dialog, ipcMain } from 'electron'
import { join } from 'path'
import { readdirSync, statSync } from 'fs'
import { SessionStore } from '../../session-store.js'
import { getMetaProjectsPath } from '../../meta-project-sync.js'
import { discoverSessions } from '../../session-discovery.js'

export function registerWorkspaceHandlers(
  sessionStore: SessionStore,
  getMainWindow: () => BrowserWindow | null
): void {
  ipcMain.handle('workspace:get', () => sessionStore.getWorkspace())
  ipcMain.handle('workspace:save', (_, workspace) => sessionStore.saveWorkspace(workspace))
  ipcMain.handle('workspace:getMetaProjectsPath', () => getMetaProjectsPath())
  ipcMain.handle('workspace:getCategoryMetaPath', (_, categoryName: string) => {
    const basePath = getMetaProjectsPath()
    // Sanitize category name for filesystem
    const safeName = categoryName.replace(/[/\\:*?"<>|]/g, '_')
    return join(basePath, safeName)
  })
  ipcMain.handle('workspace:addProject', async () => {
    const mainWindow = getMainWindow()
    const result = await dialog.showOpenDialog(mainWindow!, {
      properties: ['openDirectory'],
      title: 'Select Project Folder'
    })
    return result.canceled ? null : result.filePaths[0] || null
  })

  ipcMain.handle('workspace:addProjectsFromParent', async () => {
    const mainWindow = getMainWindow()
    const result = await dialog.showOpenDialog(mainWindow!, {
      properties: ['openDirectory'],
      title: 'Select Parent Folder (all subdirectories will be added as projects)'
    })
    if (result.canceled || !result.filePaths[0]) return null

    const parentDir = result.filePaths[0]

    try {
      const entries = readdirSync(parentDir, { withFileTypes: true })
      const subdirs = entries
        .filter((entry) => entry.isDirectory() && !entry.name.startsWith('.'))
        .map((entry) => ({
          path: join(parentDir, entry.name),
          name: entry.name
        }))
      return subdirs
    } catch (e) {
      console.error('Failed to scan parent directory:', e)
      return null
    }
  })

  // Session discovery
  ipcMain.handle('sessions:discover', (_, projectPath: string, backend?: 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider') => discoverSessions(projectPath, backend))
}

import { create } from 'zustand'
import { clearProjectCaches } from '../utils/lruCache'

export interface ProjectCategory {
  id: string
  name: string
  collapsed: boolean
  order: number
}

export interface Project {
  path: string
  name: string
  executable?: string
  apiPort?: number
  apiAutoStart?: boolean
  apiSessionMode?: 'existing' | 'new-keep' | 'new-close'
  apiModel?: 'default' | 'opus' | 'sonnet' | 'haiku'
  autoAcceptTools?: string[]
  permissionMode?: string
  color?: string
  ttsVoice?: string
  ttsEngine?: 'piper' | 'xtts'
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
  categoryId?: string
  order?: number
}

export interface OpenTab {
  id: string
  projectPath: string
  sessionId?: string
  title: string
  ptyId: string
  backend?: 'default' | 'claude' | 'gemini' | 'codex' | 'opencode' | 'aider'
}

interface WorkspaceState {
  projects: Project[]
  openTabs: OpenTab[]
  activeTabId: string | null
  categories: ProjectCategory[]

  setProjects: (projects: Project[]) => void
  addProject: (project: Project) => void
  removeProject: (path: string) => void
  updateProject: (path: string, updates: Partial<Project>) => void

  addTab: (tab: OpenTab) => void
  removeTab: (id: string) => void
  updateTab: (id: string, updates: Partial<OpenTab>) => void
  setActiveTab: (id: string) => void
  clearTabs: () => void

  setCategories: (categories: ProjectCategory[]) => void
  addCategory: (name: string) => string
  updateCategory: (id: string, updates: Partial<ProjectCategory>) => void
  removeCategory: (id: string) => void
  reorderCategories: (ids: string[]) => void
  moveProjectToCategory: (projectPath: string, categoryId: string | null) => void
  reorderProjects: (categoryId: string | null, projectPaths: string[]) => void
}

const generateCategoryId = (): string =>
  `cat-${Date.now()}-${Math.random().toString(36).substr(2, 9)}`

export const useWorkspaceStore = create<WorkspaceState>((set, get) => ({
  projects: [],
  openTabs: [],
  activeTabId: null,
  categories: [],

  setProjects: (projects) => set({ projects }),

  addProject: (project) => {
    const { projects } = get()
    if (!projects.find((p) => p.path === project.path)) {
      set({ projects: [...projects, project] })
    }
  },

  removeProject: (path) => {
    const { projects } = get()
    clearProjectCaches(path)
    set({ projects: projects.filter((p) => p.path !== path) })
  },

  updateProject: (path, updates) => {
    const { projects } = get()
    set({
      projects: projects.map((p) =>
        p.path === path ? { ...p, ...updates } : p
      )
    })
  },

  addTab: (tab) => {
    const { openTabs } = get()
    set({
      openTabs: [...openTabs, tab],
      activeTabId: tab.id
    })
  },

  removeTab: (id) => {
    const { openTabs, activeTabId } = get()
    const newTabs = openTabs.filter((t) => t.id !== id)
    let newActiveId = activeTabId

    if (activeTabId === id) {
      const index = openTabs.findIndex((t) => t.id === id)
      if (newTabs.length > 0) {
        newActiveId = newTabs[Math.min(index, newTabs.length - 1)].id
      } else {
        newActiveId = null
      }
    }

    set({ openTabs: newTabs, activeTabId: newActiveId })
  },

  updateTab: (id, updates) => {
    const { openTabs } = get()
    set({
      openTabs: openTabs.map((t) =>
        t.id === id ? { ...t, ...updates } : t
      )
    })
  },

  setActiveTab: (id) => set({ activeTabId: id }),

  clearTabs: () => set({ openTabs: [], activeTabId: null }),

  setCategories: (categories) => set({ categories }),

  addCategory: (name) => {
    const { categories } = get()
    const id = generateCategoryId()
    const maxOrder = categories.reduce((max, c) => Math.max(max, c.order), -1)
    set({
      categories: [...categories, { id, name, collapsed: false, order: maxOrder + 1 }]
    })
    return id
  },

  updateCategory: (id, updates) => {
    const { categories } = get()
    set({
      categories: categories.map((c) =>
        c.id === id ? { ...c, ...updates } : c
      )
    })
  },

  removeCategory: (id) => {
    const { categories, projects } = get()
    set({
      categories: categories.filter((c) => c.id !== id),
      projects: projects.map((p) =>
        p.categoryId === id ? { ...p, categoryId: undefined } : p
      )
    })
  },

  reorderCategories: (ids) => {
    const { categories } = get()
    set({
      categories: categories.map((c) => ({
        ...c,
        order: ids.indexOf(c.id)
      }))
    })
  },

  moveProjectToCategory: (projectPath, categoryId) => {
    const { projects } = get()
    const categoryProjects = projects.filter((p) =>
      categoryId === null ? !p.categoryId : p.categoryId === categoryId
    )
    const maxOrder = categoryProjects.reduce((max, p) => Math.max(max, p.order ?? -1), -1)
    set({
      projects: projects.map((p) =>
        p.path === projectPath
          ? { ...p, categoryId: categoryId ?? undefined, order: maxOrder + 1 }
          : p
      )
    })
  },

  reorderProjects: (categoryId, projectPaths) => {
    const { projects } = get()
    set({
      projects: projects.map((p) => {
        const index = projectPaths.indexOf(p.path)
        if (index >= 0) {
          return { ...p, order: index }
        }
        return p
      })
    })
  }
}))

/**
 * Settings Routes
 *
 * HTTP endpoints for application settings, voice configuration, and CLI status.
 */

import { Router, Request, Response } from 'express'
import {
  ApiResponse,
  Settings,
  VoiceSettings
} from '../types'
import { getServices } from '../app'

const router = Router()

// =============================================================================
// Helper Functions
// =============================================================================

function sendResponse<T>(res: Response, statusCode: number, data: ApiResponse<T>): void {
  res.status(statusCode).json(data)
}

function sendError(res: Response, statusCode: number, error: string): void {
  sendResponse(res, statusCode, {
    success: false,
    error,
    timestamp: Date.now()
  })
}

// =============================================================================
// Application Settings Routes
// =============================================================================

/**
 * GET /api/settings
 * Get application settings
 *
 * Returns: Settings
 */
router.get('/', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const settings: Settings = await services.getSettings()

    sendResponse<Settings>(res, 200, {
      success: true,
      data: settings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Settings Route] Get error:', error)
    sendError(res, 500, error.message || 'Failed to get settings')
  }
})

/**
 * PUT /api/settings
 * Save application settings
 *
 * Body: Settings
 */
router.put('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.saveSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const settings: Settings = req.body

    // Basic validation
    if (!settings || typeof settings !== 'object') {
      return sendError(res, 400, 'Invalid settings data')
    }

    await services.saveSettings(settings)

    sendResponse(res, 200, {
      success: true,
      timestamp: Date.now()
    })
  } catch (error: any) {
    console.error('[Settings Route] Save error:', error)
    sendError(res, 500, error.message || 'Failed to save settings')
  }
})

/**
 * PATCH /api/settings
 * Partially update application settings
 *
 * Body: Partial<Settings>
 */
router.patch('/', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.getSettings || !services.saveSettings) {
      return sendError(res, 503, 'Settings service not available')
    }

    const updates: Partial<Settings> = req.body

    // Get current settings and merge
    const currentSettings = await services.getSettings()
    const newSettings = { ...currentSettings, ...updates }

    await services.saveSettings(newSettings)

    sendResponse<Settings>(res, 200, {
      success: true,
      data: newSettings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to update settings')
  }
})

// =============================================================================
// Voice Settings Routes
// =============================================================================

/**
 * GET /api/settings/voice
 * Get voice settings
 *
 * Returns: VoiceSettings
 */
router.get('/voice', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceGetSettings) {
      return sendError(res, 503, 'Voice service not available')
    }

    const settings: VoiceSettings = await services.voiceGetSettings()

    sendResponse<VoiceSettings>(res, 200, {
      success: true,
      data: settings,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to get voice settings')
  }
})

/**
 * POST /api/settings/voice/speak
 * Speak text using TTS
 *
 * Body: { text: string }
 */
router.post('/voice/speak', async (req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceSpeak) {
      return sendError(res, 503, 'Voice service not available')
    }

    const { text } = req.body

    if (!text || typeof text !== 'string') {
      return sendError(res, 400, 'text is required and must be a string')
    }

    // Limit text length to prevent abuse
    if (text.length > 5000) {
      return sendError(res, 400, 'text must be 5000 characters or less')
    }

    const result = await services.voiceSpeak(text)

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      data: result.audioData ? { audioData: result.audioData } : undefined,
      error: result.error,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to speak text')
  }
})

/**
 * POST /api/settings/voice/stop
 * Stop TTS playback
 */
router.post('/voice/stop', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    if (!services.voiceStopSpeaking) {
      return sendError(res, 503, 'Voice service not available')
    }

    const result = await services.voiceStopSpeaking()

    sendResponse(res, result.success ? 200 : 500, {
      success: result.success,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to stop speaking')
  }
})

// =============================================================================
// CLI Status Routes
// =============================================================================

/**
 * GET /api/settings/cli/status
 * Get installation status of all CLI tools
 *
 * Returns: { claude, gemini, codex, opencode, aider }
 */
router.get('/cli/status', async (_req: Request, res: Response) => {
  try {
    const services = getServices()

    const status: Record<string, any> = {}

    // Check each CLI tool in parallel
    const checks = await Promise.allSettled([
      services.claudeCheck?.() ?? Promise.resolve({ installed: false }),
      services.geminiCheck?.() ?? Promise.resolve({ installed: false }),
      services.codexCheck?.() ?? Promise.resolve({ installed: false }),
      services.opencodeCheck?.() ?? Promise.resolve({ installed: false }),
      services.aiderCheck?.() ?? Promise.resolve({ installed: false })
    ])

    const cliNames = ['claude', 'gemini', 'codex', 'opencode', 'aider']

    checks.forEach((result, index) => {
      if (result.status === 'fulfilled') {
        status[cliNames[index]] = result.value
      } else {
        status[cliNames[index]] = { installed: false, error: result.reason?.message }
      }
    })

    sendResponse(res, 200, {
      success: true,
      data: status,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check CLI status')
  }
})

/**
 * GET /api/settings/cli/:tool
 * Get installation status of a specific CLI tool
 *
 * Params: tool - one of: claude, gemini, codex, opencode, aider
 */
router.get('/cli/:tool', async (req: Request, res: Response) => {
  try {
    const services = getServices()
    const { tool } = req.params

    const checkFunctions: Record<string, (() => Promise<any>) | undefined> = {
      claude: services.claudeCheck,
      gemini: services.geminiCheck,
      codex: services.codexCheck,
      opencode: services.opencodeCheck,
      aider: services.aiderCheck
    }

    const checkFn = checkFunctions[tool]
    if (!checkFn) {
      return sendError(res, 400, `Unknown tool: ${tool}. Valid tools: ${Object.keys(checkFunctions).join(', ')}`)
    }

    const result = await checkFn()

    sendResponse(res, 200, {
      success: true,
      data: result,
      timestamp: Date.now()
    })
  } catch (error: any) {
    sendError(res, 500, error.message || 'Failed to check CLI status')
  }
})

export default router

/**
 * Workspace API Methods
 *
 * Workspace, settings, session, TTS, and project management methods for the HTTP backend.
 */

import {
  Settings,
  Workspace,
  Session,
  ApiOpenSessionCallback,
  Unsubscribe,
  BackendId
} from '../types'
import { ConnectionManager } from './connection'

export class WorkspaceApi {
  private connection: ConnectionManager
  private apiOpenSessionCallbacks: Set<ApiOpenSessionCallback> = new Set()

  constructor(connection: ConnectionManager) {
    this.connection = connection
  }

  // Session Management

  async discoverSessions(projectPath: string, backend?: BackendId): Promise<Session[]> {
    const params = new URLSearchParams({ path: projectPath })
    if (backend) {
      params.set('backend', backend)
    }

    const data = await this.connection.fetchJson<{ sessions: Session[] }>(
      `/api/sessions?${params}`
    )
    return data.sessions
  }

  // Workspace Management

  async getWorkspace(): Promise<Workspace> {
    return this.connection.fetchJson<Workspace>('/api/workspace')
  }

  async saveWorkspace(_workspace: Workspace): Promise<void> {
    // NO-OP: Browser/mobile should NOT save workspace back to desktop
    // The Electron desktop app is the source of truth for workspace data
    // This prevents browser from accidentally wiping desktop's projects
    console.log('[HttpBackend] saveWorkspace() ignored - desktop is source of truth')
  }

  // Settings Management

  async getSettings(): Promise<Settings> {
    return this.connection.fetchJson<Settings>('/api/settings')
  }

  async saveSettings(settings: Settings): Promise<void> {
    await this.connection.fetchJson('/api/settings', {
      method: 'POST',
      body: JSON.stringify(settings)
    })
  }

  // Project Management

  async addProject(): Promise<string | null> {
    // HTTP backend cannot open a native file dialog on the desktop
    // Instead, mobile clients should browse/select paths differently
    // This could be implemented via a file browser endpoint in the future
    console.warn('[HttpBackend] addProject() - Native dialogs not available via HTTP')
    return null
  }

  async addProjectsFromParent(): Promise<Array<{ path: string; name: string }> | null> {
    // HTTP backend cannot open a native file dialog on the desktop
    console.warn('[HttpBackend] addProjectsFromParent() - Native dialogs not available via HTTP')
    return null
  }

  // TTS (Text-to-Speech)

  async ttsInstallInstructions(projectPath: string): Promise<{ success: boolean }> {
    // TTS instruction installation is a desktop-only feature
    // The mobile app uses the host's TTS directly
    console.warn('[HttpBackend] ttsInstallInstructions() - Desktop-only feature')
    return { success: false }
  }

  async ttsSpeak(
    text: string
  ): Promise<{ success: boolean; audioData?: string; error?: string }> {
    try {
      const data = await this.connection.fetchJson<{
        success: boolean
        audioData?: string
        error?: string
        format?: string
      }>('/api/tts/speak', {
        method: 'POST',
        body: JSON.stringify({ text })
      })
      return data
    } catch (error) {
      return {
        success: false,
        error: error instanceof Error ? error.message : 'TTS failed'
      }
    }
  }

  async ttsStop(): Promise<{ success: boolean }> {
    try {
      return await this.connection.fetchJson<{ success: boolean }>('/api/tts/stop', {
        method: 'POST'
      })
    } catch (error) {
      return { success: false }
    }
  }

  // Events

  onApiOpenSession(callback: ApiOpenSessionCallback): Unsubscribe {
    // API open session events would come via WebSocket from the main connection
    // For now, this is primarily used in the desktop app
    // Mobile clients don't typically receive these events
    this.apiOpenSessionCallbacks.add(callback)
    return () => {
      this.apiOpenSessionCallbacks.delete(callback)
    }
  }
}

