    22→    this.connection = connection
    23→  }
    24→
    25→  // Session Management
    26→
    27→  async discoverSessions(projectPath: string, backend?: BackendId): Promise<Session[]> {
    28→    const params = new URLSearchParams({ path: projectPath })
    29→    if (backend) {
    30→      params.set('backend', backend)
    31→    }
    32→
    33→    const data = await this.connection.fetchJson<{ sessions: Session[] }>(
    34→      `/api/sessions?${params}`
    35→    )
    36→    return data.sessions
    37→  }
    38→
    39→  // Workspace Management
    40→
    41→  async getWorkspace(): Promise<Workspace> {
    42→    return this.connection.fetchJson<Workspace>('/api/workspace')
    43→  }
    44→
    45→  async saveWorkspace(_workspace: Workspace): Promise<void> {
    46→    // NO-OP: Browser/mobile should NOT save workspace back to desktop
    47→    // The Electron desktop app is the source of truth for workspace data
    48→    // This prevents browser from accidentally wiping desktop's projects
    49→    console.log('[HttpBackend] saveWorkspace() ignored - desktop is source of truth')
    50→  }
    51→
    52→  // Settings Management
    53→
    54→  async getSettings(): Promise<Settings> {
    55→    return this.connection.fetchJson<Settings>('/api/settings')
    56→  }
    57→
    58→  async saveSettings(settings: Settings): Promise<void> {
    59→    await this.connection.fetchJson('/api/settings', {
    60→      method: 'POST',
    61→      body: JSON.stringify(settings)
    62→    })
    63→  }
    64→
    65→  // Project Management
    66→
    67→  async addProject(): Promise<string | null> {
    68→    // HTTP backend cannot open a native file dialog on the desktop
    69→    // Instead, mobile clients should browse/select paths differently
    70→    // This could be implemented via a file browser endpoint in the future
    71→    console.warn('[HttpBackend] addProject() - Native dialogs not available via HTTP')
    72→    return null
    73→  }
    74→
    75→  async addProjectsFromParent(): Promise<Array<{ path: string; name: string }> | null> {
    76→    // HTTP backend cannot open a native file dialog on the desktop
    77→    console.warn('[HttpBackend] addProjectsFromParent() - Native dialogs not available via HTTP')
    78→    return null
    79→  }
    80→
    81→  // TTS (Text-to-Speech)
    82→
    83→  async ttsInstallInstructions(projectPath: string): Promise<{ success: boolean }> {
    84→    // TTS instruction installation is a desktop-only feature
    85→    // The mobile app uses the host's TTS directly
    86→    console.warn('[HttpBackend] ttsInstallInstructions() - Desktop-only feature')
    87→    return { success: false }
    88→  }
    89→
    90→  async ttsSpeak(
    91→    text: string
    92→  ): Promise<{ success: boolean; audioData?: string; error?: string }> {
    93→    try {
    94→      const data = await this.connection.fetchJson<{
    95→        success: boolean
    96→        audioData?: string
    97→        error?: string
    98→        format?: string
    99→      }>('/api/tts/speak', {
   100→        method: 'POST',
   101→        body: JSON.stringify({ text })
   102→      })
   103→      return data
   104→    } catch (error) {
   105→      return {
   106→        success: false,
   107→        error: error instanceof Error ? error.message : 'TTS failed'
   108→      }
   109→    }
   110→  }
   111→
   112→  async ttsStop(): Promise<{ success: boolean }> {
   113→    try {
   114→      return await this.connection.fetchJson<{ success: boolean }>('/api/tts/stop', {
   115→        method: 'POST'
   116→      })
   117→    } catch (error) {
   118→      return { success: false }
   119→    }
   120→  }
   121→
   122→  // Events
   123→
   124→  onApiOpenSession(callback: ApiOpenSessionCallback): Unsubscribe {
   125→    // API open session events would come via WebSocket from the main connection
   126→    // For now, this is primarily used in the desktop app
   127→    // Mobile clients don't typically receive these events
   128→    this.apiOpenSessionCallbacks.add(callback)
   129→    return () => {
   130→      this.apiOpenSessionCallbacks.delete(callback)
   131→    }
   132→  }
   133→}
