import { useEffect, useRef, useState, useCallback } from 'react'
import type { Api } from '../api'
import type { BackendId } from '../api/types'
import type { AppSettings } from './useSettings'
import { useWorkspaceStore } from '../stores/workspace'
import { Theme, getThemeById, applyTheme, themes } from '../themes'
import { cleanupOrphanedBuffers } from '../components/terminal/Terminal'

interface UseWorkspaceLoaderOptions {
  api: Api
  checkInstallation: () => Promise<void>
  setViewMode: (mode: 'tabs' | 'tiled') => void
  setTileLayout: (layout: any[]) => void
}

interface UseWorkspaceLoaderReturn {
  loading: boolean
  currentTheme: Theme
  settings: AppSettings | null
  setCurrentTheme: (theme: Theme) => void
  setSettings: (settings: AppSettings | null) => void
}

export function useWorkspaceLoader({
  api,
  checkInstallation,
  setViewMode,
  setTileLayout
}: UseWorkspaceLoaderOptions): UseWorkspaceLoaderReturn {
  const {
    setProjects,
    setCategories,
    addTab,
    clearTabs
  } = useWorkspaceStore()

  const [loading, setLoading] = useState(true)
  const [currentTheme, setCurrentTheme] = useState<Theme>(themes[0])
  const [settings, setSettings] = useState<AppSettings | null>(null)
  const initRef = useRef(false)
  const hadProjectsRef = useRef(false)

  // Load workspace on mount and restore tabs
  useEffect(() => {
    // Prevent double initialization from StrictMode
    if (initRef.current) return
    initRef.current = true

    const loadWorkspace = async () => {
      try {
        // Check if Claude, npm, and git-bash are installed
        await checkInstallation()

        // Load and apply theme with any saved customizations
        const loadedSettings = await api.getSettings()
        setSettings(loadedSettings)
        const theme = getThemeById(loadedSettings.theme || 'default')
        applyTheme(theme, loadedSettings.themeCustomization)
        setCurrentTheme(theme)

        // Kill any existing PTYs from hot reload (but don't clear buffers - they'll be restored)
        const existingTabs = useWorkspaceStore.getState().openTabs
        for (const tab of existingTabs) {
          api.killPty(tab.id)
        }
        clearTabs()

        const workspace = await api.getWorkspace()
        if (workspace.projects) {
          setProjects(workspace.projects)
          if (workspace.projects.length > 0) {
            hadProjectsRef.current = true
          }
          // Install TTS instructions for all existing projects
          for (const project of workspace.projects) {
            await api.ttsInstallInstructions?.(project.path)
          }
        }
        // Load categories
        if (workspace.categories) {
          setCategories(workspace.categories)
        }

        // Restore previously open tabs (only if not already open)
        // Track old ID -> new ID mapping for layout restoration
        const idMapping = new Map<string, string>()

        if (workspace.openTabs && workspace.openTabs.length > 0) {
          const currentTabs = useWorkspaceStore.getState().openTabs
          const usedSessionIds = new Set(currentTabs.map(t => t.sessionId).filter(Boolean))
          const sessionsCache = new Map<string, { list: { sessionId: string; slug: string }[]; nextIndex: number }>()

          for (const savedTab of workspace.openTabs) {
            try {
              // Always install TTS instructions so Claude uses <tts> tags
              await api.ttsInstallInstructions?.(savedTab.projectPath)

              const projectName = savedTab.projectPath.split(/[/\\]/).pop() || savedTab.projectPath
              let titleToRestore = savedTab.title || `${projectName} - New`

              // Get project and determine effective backend for restored tab
              const projectForTab = workspace.projects?.find((p: { path: string }) => p.path === savedTab.projectPath)
              const savedBackend = savedTab.backend
              const effectiveBackendForTab = (savedBackend
                || (projectForTab?.backend && projectForTab.backend !== 'default'
                  ? projectForTab.backend
                  : (loadedSettings?.backend && loadedSettings.backend !== 'default'
                    ? loadedSettings.backend
                    : 'claude'))) as BackendId

              let sessionIdToRestore: string | undefined = savedTab.sessionId

              // Always discover sessions to find the most recent one
              let sessionsForProject = sessionsCache.get(savedTab.projectPath)
              if (!sessionsForProject) {
                const list = await api.discoverSessions(savedTab.projectPath, effectiveBackendForTab)
                sessionsForProject = { list, nextIndex: 0 }
                sessionsCache.set(savedTab.projectPath, sessionsForProject)
              }

              const list = sessionsForProject.list || []
              for (let i = sessionsForProject.nextIndex; i < list.length; i++) {
                const candidate = list[i]
                if (!usedSessionIds.has(candidate.sessionId)) {
                  sessionIdToRestore = candidate.sessionId
                  titleToRestore = `${projectName} - ${candidate.slug}`
                  sessionsForProject.nextIndex = i + 1
                  break
                }
              }

              const ptyId = await api.spawnPty(
                savedTab.projectPath,
                sessionIdToRestore,
                undefined,
                effectiveBackendForTab
              )
              if (savedTab.id) {
                idMapping.set(savedTab.id, ptyId)
              }

              addTab({
                id: ptyId,
                projectPath: savedTab.projectPath,
                sessionId: sessionIdToRestore,
                title: titleToRestore,
                ptyId,
                backend: effectiveBackendForTab
              })
              if (sessionIdToRestore) {
                usedSessionIds.add(sessionIdToRestore)
              }
            } catch (e) {
              console.error('Failed to restore tab:', savedTab.projectPath, e)
            }
          }
        }

        // Clean up orphaned terminal buffers from previous session/HMR
        const activeTabIds = useWorkspaceStore.getState().openTabs.map(t => t.id)
        cleanupOrphanedBuffers(activeTabIds)

        // Restore view mode
        if (workspace.viewMode) {
          setViewMode(workspace.viewMode)
        }
        // Restore tileLayout with mapped IDs and migrate legacy format
        if (workspace.tileLayout && workspace.tileLayout.length > 0 && idMapping.size > 0) {
          const mappedLayout = workspace.tileLayout
            .map(tile => {
              // Migrate legacy tiles: add tabIds/activeTabId if missing
              const tabIds = tile.tabIds || [tile.id]
              const mappedTabIds = tabIds
                .map(id => idMapping.get(id) || id)
                .filter(id => {
                  // Only keep tab IDs that exist in the current session
                  const currentTabs = useWorkspaceStore.getState().openTabs
                  return currentTabs.some(t => t.id === id)
                })

              if (mappedTabIds.length === 0) return null

              const newId = idMapping.get(tile.id) || mappedTabIds[0]
              const activeTabId = tile.activeTabId
                ? (idMapping.get(tile.activeTabId) || mappedTabIds[0])
                : mappedTabIds[0]

              return {
                ...tile,
                id: newId,
                tabIds: mappedTabIds,
                activeTabId
              }
            })
            .filter((tile): tile is NonNullable<typeof tile> => tile !== null)

          if (mappedLayout.length > 0) {
            setTileLayout(mappedLayout)
          }
        }
      } catch (e) {
        console.error('Failed to load workspace:', e)
      }
      setLoading(false)
    }
    loadWorkspace()
  }, [api, addTab, clearTabs, checkInstallation, setProjects, setCategories, setViewMode, setTileLayout])

  return {
    loading,
    currentTheme,
    settings,
    setCurrentTheme,
    setSettings
  }
}

import { useCallback, useRef } from 'react'
import { Project, useWorkspaceStore } from '../../stores/workspace.js'
import { SidebarState } from './useSidebarState.js'
import { SidebarProps } from './types.js'

// Use type assertion for extended electronAPI methods not in the base type
const electronAPI = window.electronAPI as (typeof window.electronAPI) & {
  selectExecutable?: () => Promise<string | null>
  runExecutable?: (executable: string, cwd: string) => Promise<{ success: boolean; error?: string }>
  getCategoryMetaPath?: (categoryName: string) => Promise<string>
  getMetaProjectsPath?: () => Promise<string>
}

export interface SidebarHandlers {
  // Project handlers
  handleSelectExecutable: (project: Project) => Promise<void>
  handleClearExecutable: (project: Project) => void
  handleRunExecutable: (project: Project) => Promise<void>

  // Rename handlers
  handleStartRename: (e: React.MouseEvent, project: Project) => void
  handleRenameSubmit: () => void
  handleRenameKeyDown: (e: React.KeyboardEvent) => void

  // Category handlers
  handleAddCategory: () => void
  handleOpenCategoryAsProject: (categoryName: string) => Promise<void>
  handleOpenAllProjects: () => Promise<void>
  handleStartCategoryRename: (
    category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]
  ) => void
  handleCategoryRenameSubmit: () => void
  handleCategoryRenameKeyDown: (e: React.KeyboardEvent) => void
  toggleCategoryCollapse: (categoryId: string) => void

  // Resize handler
  handleMouseDown: (e: React.MouseEvent) => void

  // Backdrop handler
  handleBackdropClick: () => void
}

export interface UseSidebarHandlersParams {
  state: SidebarState
  onUpdateProject: SidebarProps['onUpdateProject']
  onOpenSession: SidebarProps['onOpenSession']
  isMobile: boolean
  onMobileClose: (() => void) | undefined
}

export function useSidebarHandlers(params: UseSidebarHandlersParams): SidebarHandlers {
  const { state, onUpdateProject, onOpenSession, isMobile, onMobileClose } = params
  const {
    setContextMenu,
    editingProject,
    setEditingProject,
    editInputRef,
    editingCategory,
    setEditingCategory,
    categoryEditInputRef,
    addCategory,
    updateCategory,
    categories,
    setIsResizing,
    moveProjectToCategory,
  } = state

  // Project handlers
  const handleSelectExecutable = useCallback(
    async (project: Project) => {
      const executable = await electronAPI?.selectExecutable?.()
      if (executable) onUpdateProject(project.path, { executable })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleClearExecutable = useCallback(
    (project: Project) => {
      onUpdateProject(project.path, { executable: undefined })
      setContextMenu(null)
    },
    [onUpdateProject, setContextMenu]
  )

  const handleRunExecutable = useCallback(
    async (project: Project) => {
      if (project.executable) {
        const result = await electronAPI?.runExecutable?.(project.executable, project.path)
        if (result && !result.success) console.error('Failed to run executable:', result.error)
      }
      setContextMenu(null)
    },
    [setContextMenu]
  )

  // Rename handlers
  // Ref tracks cancel intent so blur handler can skip saving after Escape
  const renameCancelledRef = useRef(false)

  const handleStartRename = useCallback(
    (e: React.MouseEvent, project: Project) => {
      e.stopPropagation()
      renameCancelledRef.current = false
      setEditingProject({ path: project.path, name: project.name })
      setTimeout(() => editInputRef.current?.select(), 0)
    },
    [setEditingProject, editInputRef]
  )

  const handleRenameSubmit = useCallback(() => {
    if (renameCancelledRef.current) {
      renameCancelledRef.current = false
      return
    }
    if (editingProject && editingProject.name.trim()) {
      onUpdateProject(editingProject.path, { name: editingProject.name.trim() })
    }
    setEditingProject(null)
  }, [editingProject, onUpdateProject, setEditingProject])

  const handleRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleRenameSubmit()
      else if (e.key === 'Escape') {
        renameCancelledRef.current = true
        setEditingProject(null)
      }
    },
    [handleRenameSubmit, setEditingProject]
  )

  // Category handlers
  const handleAddCategory = useCallback(() => {
    const newId = addCategory('New Category')
    setEditingCategory({ id: newId, name: 'New Category' })
    setTimeout(() => categoryEditInputRef.current?.select(), 0)
  }, [addCategory, setEditingCategory, categoryEditInputRef])

  const handleOpenCategoryAsProject = useCallback(
    async (categoryName: string) => {
      const metaPath = await electronAPI?.getCategoryMetaPath?.(categoryName)
      if (metaPath) onOpenSession(metaPath)
    },
    [onOpenSession]
  )

  const handleOpenAllProjects = useCallback(async () => {
    const metaPath = await electronAPI?.getMetaProjectsPath?.()
    if (metaPath) onOpenSession(metaPath)
  }, [onOpenSession])

  // Category rename cancel ref (same pattern as project rename)
  const categoryRenameCancelledRef = useRef(false)

  const handleStartCategoryRename = useCallback(
    (category: ReturnType<typeof useWorkspaceStore.getState>['categories'][0]) => {
      categoryRenameCancelledRef.current = false
      setEditingCategory({ id: category.id, name: category.name })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [setEditingCategory, categoryEditInputRef]
  )

  const handleCategoryRenameSubmit = useCallback(() => {
    if (categoryRenameCancelledRef.current) {
      categoryRenameCancelledRef.current = false
      return
    }
    if (editingCategory && editingCategory.name.trim()) {
      updateCategory(editingCategory.id, { name: editingCategory.name.trim() })
    }
    setEditingCategory(null)
  }, [editingCategory, updateCategory, setEditingCategory])

  const handleCategoryRenameKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') handleCategoryRenameSubmit()
      else if (e.key === 'Escape') {
        categoryRenameCancelledRef.current = true
        setEditingCategory(null)
      }
    },
    [handleCategoryRenameSubmit, setEditingCategory]
  )

  const toggleCategoryCollapse = useCallback(
    (categoryId: string) => {
      const category = categories.find((c) => c.id === categoryId)
      if (category) updateCategory(categoryId, { collapsed: !category.collapsed })
    },
    [categories, updateCategory]
  )

  // Resize handler
  const handleMouseDown = useCallback(
    (e: React.MouseEvent) => {
      e.preventDefault()
      setIsResizing(true)
    },
    [setIsResizing]
  )

  // Backdrop handler
  const handleBackdropClick = useCallback(() => {
    if (isMobile && onMobileClose) {
      onMobileClose()
    }
  }, [isMobile, onMobileClose])

  return {
    handleSelectExecutable,
    handleClearExecutable,
    handleRunExecutable,
    handleStartRename,
    handleRenameSubmit,
    handleRenameKeyDown,
    handleAddCategory,
    handleOpenCategoryAsProject,
    handleOpenAllProjects,
    handleStartCategoryRename,
    handleCategoryRenameSubmit,
    handleCategoryRenameKeyDown,
    toggleCategoryCollapse,
    handleMouseDown,
    handleBackdropClick,
  }
}

// Helper for creating category with project
export function useCreateCategoryWithProject(
  state: SidebarState
): (projectPath: string) => void {
  const { addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef } = state

  return useCallback(
    (projectPath: string) => {
      const newId = addCategory('New Category')
      moveProjectToCategory(projectPath, newId)
      setContextMenu(null)
      setEditingCategory({ id: newId, name: 'New Category' })
      setTimeout(() => categoryEditInputRef.current?.select(), 0)
    },
    [addCategory, moveProjectToCategory, setContextMenu, setEditingCategory, categoryEditInputRef]
  )
}

import { app } from 'electron'
import { existsSync, mkdirSync, readdirSync, lstatSync, readlinkSync, unlinkSync, rmSync, symlinkSync } from 'fs'
import { join } from 'path'
import type { Workspace, Project, ProjectCategory } from './session-store'

const UNCATEGORIZED_FOLDER = 'Uncategorized'

/**
 * Get the base path for meta-projects symlink structure
 */
function getMetaProjectsBasePath(): string {
  return join(app.getPath('userData'), 'meta-projects')
}

/**
 * Get current symlinks in a category directory
 * Returns map of symlink name -> target path
 */
function getCurrentSymlinks(categoryDir: string): Map<string, string> {
  const symlinks = new Map<string, string>()
  if (!existsSync(categoryDir)) return symlinks

  try {
    const entries = readdirSync(categoryDir)
    for (const entry of entries) {
      const entryPath = join(categoryDir, entry)
      try {
        const stat = lstatSync(entryPath)
        if (stat.isSymbolicLink()) {
          const target = readlinkSync(entryPath)
          symlinks.set(entry, target)
        }
      } catch {
        // Skip entries we can't stat
      }
    }
  } catch {
    // Directory might not exist or be readable
  }
  return symlinks
}

/**
 * Remove a single symlink
 */
function removeSymlink(symlinkPath: string): void {
  try {
    if (existsSync(symlinkPath)) {
      const stat = lstatSync(symlinkPath)
      if (stat.isSymbolicLink()) {
        unlinkSync(symlinkPath)
      }
    }
  } catch (e) {
    console.warn(`Failed to remove symlink ${symlinkPath}:`, e)
  }
}

/**
 * Remove an empty category directory (only if it's empty)
 */
function removeEmptyCategoryDir(categoryDir: string): void {
  if (!existsSync(categoryDir)) return

  try {
    const entries = readdirSync(categoryDir)
    if (entries.length === 0) {
      rmSync(categoryDir, { recursive: true, force: true })
    }
  } catch (e) {
    console.warn(`Failed to remove empty category dir ${categoryDir}:`, e)
  }
}

/**
 * Generate a unique symlink name by appending numbers if needed
 */
function getUniqueSymlinkName(dir: string, baseName: string, existingNames: Set<string>): string {
  // Sanitize name for filesystem
  let name = baseName.replace(/[/\\:*?"<>|]/g, '_')

  if (!existingNames.has(name)) {
    existingNames.add(name)
    return name
  }

  // Append numbers until unique
  let counter = 2
  while (existingNames.has(`${name}-${counter}`)) {
    counter++
  }

  const uniqueName = `${name}-${counter}`
  existingNames.add(uniqueName)
  return uniqueName
}

/**
 * Create a symlink, handling errors gracefully
 */
function createSymlink(targetPath: string, symlinkPath: string): boolean {
  try {
    // Verify target path exists
    if (!existsSync(targetPath)) {
      console.warn(`Skipping symlink for non-existent path: ${targetPath}`)
      return false
    }

    symlinkSync(targetPath, symlinkPath)
    return true
  } catch (e) {
    console.warn(`Failed to create symlink ${symlinkPath} -> ${targetPath}:`, e)
    return false
  }
}

/**
 * Build category map from workspace
 */
function buildCategoryMap(categories: ProjectCategory[] | undefined): Map<string, string> {
  const map = new Map<string, string>()
  if (categories) {
    for (const cat of categories) {
      map.set(cat.id, cat.name)
    }
  }
  return map
}

/**
 * Group projects by category
 */
function groupProjectsByCategory(
  projects: Project[],
  categoryMap: Map<string, string>
): Map<string, Project[]> {
  const groups = new Map<string, Project[]>()

  for (const project of projects) {
    let categoryName: string

    if (project.categoryId && categoryMap.has(project.categoryId)) {
      categoryName = categoryMap.get(project.categoryId)!
    } else {
      categoryName = UNCATEGORIZED_FOLDER
    }

    // Sanitize category name for filesystem
    categoryName = categoryName.replace(/[/\\:*?"<>|]/g, '_')

    if (!groups.has(categoryName)) {
      groups.set(categoryName, [])
    }
    groups.get(categoryName)!.push(project)
  }

  return groups
}

/**
 * Sync workspace projects to meta-projects symlink structure
 *
 * Creates a hierarchical symlink structure mirroring workspace categories:
 * ~/.config/simple-code-gui/meta-projects/
 * ├── Work/
 * │   ├── ProjectA -> /home/user/work/ProjectA
 * │   └── ProjectB -> /home/user/work/ProjectB
 * ├── Personal/
 * │   └── MyApp -> /home/user/Projects/MyApp
 * └── Uncategorized/
 *     └── RandomProject -> /home/user/RandomProject
 *
 * IMPORTANT: This function does incremental updates to avoid breaking
 * running sessions that have their cwd in a category folder. It only
 * removes/adds symlinks as needed rather than deleting entire directories.
 */
export function syncMetaProjects(workspace: Workspace): void {
  const basePath = getMetaProjectsBasePath()

  // Ensure base directory exists
  if (!existsSync(basePath)) {
    try {
      mkdirSync(basePath, { recursive: true })
    } catch (e) {
      console.error('Failed to create meta-projects directory:', e)
      return
    }
  }

  // Build category mapping
  const categoryMap = buildCategoryMap(workspace.categories)

  // Group projects by category
  const projectGroups = groupProjectsByCategory(workspace.projects, categoryMap)

  // Track which category dirs should exist
  const expectedCategoryDirs = new Set<string>()
  for (const categoryName of projectGroups.keys()) {
    expectedCategoryDirs.add(categoryName)
  }

  // Process each category - add/update symlinks
  for (const [categoryName, projects] of projectGroups) {
    const categoryDir = join(basePath, categoryName)

    // Create category directory if it doesn't exist
    if (!existsSync(categoryDir)) {
      try {
        mkdirSync(categoryDir, { recursive: true })
      } catch (e) {
        console.warn(`Failed to create category directory ${categoryDir}:`, e)
        continue
      }
    }

    // Get current symlinks in this category
    const currentSymlinks = getCurrentSymlinks(categoryDir)

    // Build map of what symlinks should exist (project path -> desired symlink name)
    const desiredSymlinks = new Map<string, string>()
    const usedNames = new Set<string>()

    for (const project of projects) {
      const symlinkName = getUniqueSymlinkName(categoryDir, project.name, usedNames)
      desiredSymlinks.set(project.path, symlinkName)
    }

    // Remove symlinks that shouldn't exist or point to wrong targets
    for (const [name, target] of currentSymlinks) {
      // Check if this symlink is still needed
      let shouldKeep = false
      for (const [projectPath, desiredName] of desiredSymlinks) {
        if (target === projectPath && name === desiredName) {
          shouldKeep = true
          break
        }
      }
      if (!shouldKeep) {
        removeSymlink(join(categoryDir, name))
      }
    }

    // Refresh current symlinks after removals
    const remainingSymlinks = getCurrentSymlinks(categoryDir)
    const existingTargets = new Set(remainingSymlinks.values())

    // Create new symlinks that don't exist yet
    for (const [projectPath, symlinkName] of desiredSymlinks) {
      if (!existingTargets.has(projectPath)) {
        createSymlink(projectPath, join(categoryDir, symlinkName))
      }
    }
  }

  // Remove category directories that shouldn't exist anymore
  // But only remove symlinks inside, keep the directory if it still has content
  try {
    const existingDirs = readdirSync(basePath)
    for (const dirName of existingDirs) {
      if (!expectedCategoryDirs.has(dirName)) {
        const dirPath = join(basePath, dirName)
        const stat = lstatSync(dirPath)
        if (stat.isDirectory() && !stat.isSymbolicLink()) {
          // Remove all symlinks in this directory
          const symlinks = getCurrentSymlinks(dirPath)
          for (const name of symlinks.keys()) {
            removeSymlink(join(dirPath, name))
          }
          // Try to remove directory if empty
          removeEmptyCategoryDir(dirPath)
        }
      }
    }
  } catch (e) {
    console.warn('Failed to clean up old category directories:', e)
  }
}

